1	// Ann's PHI Clipbuddy — frontend
2	// On window focus: consume clipboard via Tauri IPC, render triage view
3	
4	let triageData = null;   // { findings, plain_text } from last clinical result
5	let toggleStates = [];   // parallel to findings: "elide" or "pass"
6	
7	// ---------------------------------------------------------------------------
8	// Focus handler — invoke backend on every window focus
9	// ---------------------------------------------------------------------------
10	
11	window.addEventListener("focus", async () => {
12	  try {
13	    const result = await window.__TAURI__.core.invoke("consume_clipboard");
14	    zapcapHandleResult(result);
15	  } catch (e) {
16	    document.getElementById("diagnostic").textContent = "Error: " + e;
17	  }
18	});
19	
20	// ---------------------------------------------------------------------------
21	// Result dispatch
22	// ---------------------------------------------------------------------------
23	
24	function zapcapHandleResult(result) {
25	  switch (result.type) {
26	    case "unchanged":
27	      break;
28	    case "clinical":
29	      zapcapShowTriage(result);
30	      break;
31	    case "non_clinical":
32	      zapcapShowNonClinical(result);
33	      break;
34	  }
35	}
36	
37	// ---------------------------------------------------------------------------
38	// Non-clinical state — show diagnostic, return to instruction view
39	// ---------------------------------------------------------------------------
40	
41	function zapcapShowNonClinical(result) {
42	  triageData = null;
43	  toggleStates = [];
44	  document.getElementById("instruction-state").style.display = "";
45	  document.getElementById("triage-state").style.display = "none";
46	  document.getElementById("diagnostic").textContent =
47	    "Not clinical (" + result.content_length + " bytes, " +
48	    result.content_type + "): " + result.preview;
49	}
50	
51	// ---------------------------------------------------------------------------
52	// Triage state — document preview + findings panel
53	// ---------------------------------------------------------------------------
54	
55	function zapcapShowTriage(result) {
56	  triageData = result;
57	  toggleStates = result.findings.map(function() { return "elide"; });
58	
59	  document.getElementById("instruction-state").style.display = "none";
60	  document.getElementById("triage-state").style.display = "";
61	
62	  zapcapRenderPreview();
63	  zapcapRenderFindings();
64	}
65	
66	// ---------------------------------------------------------------------------
67	// Document preview — plain text with inline PHI highlights
68	// ---------------------------------------------------------------------------
69	
70	function zapcapRenderPreview() {
71	  var plain = triageData.plain_text;
72	  var findings = triageData.findings;
73	
74	  // Build index-annotated list sorted by offset
