body {
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
  margin: 0;
  padding: 20px;
  background: #f5f5f5;
  color: #333;
}

#app {
  max-width: 960px;
  margin: 0 auto;
}

h1 {
  color: #2c3e50;
  margin: 0 0 12px 0;
  font-size: 20px;
}

/* --- Instruction state --- */

.instruction {
  color: #666;
  font-size: 14px;
  line-height: 1.6;
}

.diagnostic {
  color: #888;
  font-size: 12px;
  font-family: monospace;
  margin-top: 8px;
}

/* --- Document preview --- */

#document-preview {
  background: #fff;
  border: 1px solid #ddd;
  padding: 16px;
  font-size: 13px;
  line-height: 1.6;
  white-space: pre-wrap;
  word-wrap: break-word;
  max-height: 340px;
  overflow-y: auto;
  margin-bottom: 12px;
}

/* --- PHI highlights in document preview --- */

.phi-red {
  background: #ff000030;
  border: 2px solid red;
  border-radius: 2px;
  padding: 0 2px;
}

.phi-yellow {
  background: #ffff0030;
  border: 2px solid orange;
  border-radius: 2px;
  padding: 0 2px;
}

.phi-pass {
  color: #999;
}

/* --- Findings panel --- */

#findings-panel {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.findings-section {
  background: #fff;
  border: 1px solid #ddd;
  padding: 12px;
}

.findings-section h3 {
  margin: 0 0 8px 0;
  font-size: 13px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

#findings-yellow h3 { color: #b8860b; }
#findings-red h3 { color: #cc0000; }

.findings-list {
  max-height: 200px;
  overflow-y: auto;
}

.finding-entry {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 4px 0;
  font-size: 12px;
  border-bottom: 1px solid #eee;
}

.finding-entry:last-child {
  border-bottom: none;
}

.finding-text {
  font-family: monospace;
  font-weight: 600;
  min-width: 80px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  max-width: 200px;
}

.finding-category {
  color: #666;
  font-size: 11px;
  min-width: 60px;
}

.finding-toggle {
  margin-left: auto;
  padding: 2px 8px;
  border: 1px solid #ccc;
  border-radius: 3px;
  background: #f9f9f9;
  cursor: pointer;
  font-size: 11px;
  white-space: nowrap;
}

.finding-toggle.elide {
  background: #fee;
  border-color: #daa;
}

.finding-toggle.pass {
  background: #efe;
  border-color: #ada;
}

.empty-section {
  color: #999;
  font-size: 12px;
  font-style: italic;
}

