    use chrono::NaiveDate;

    const FIXTURE_PROGRESS: &str = include_str!("../../test_fixtures/epic_progress_note.html");

    fn today() -> NaiveDate {
        NaiveDate::from_ymd_opt(2026, 4, 10).unwrap()
